namespace sv_84271e90bece4b058355549cf0d4246c.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
}

using sv_84271e90bece4b058355549cf0d4246c.Client.Models;

namespace sv_84271e90bece4b058355549cf0d4246c.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_84271e90bece4b058355549cf0d4246c.Client.Models;
using sv_84271e90bece4b058355549cf0d4246c.Client.Services;

namespace sv_84271e90bece4b058355549cf0d4246c.Services;

public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 25, 10, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Arrived at sorting facility", Timestamp = new DateTimeOffset(2026, 5, 26, 3, 30, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Departed Memphis hub", Timestamp = new DateTimeOffset(2026, 5, 27, 14, 15, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "Seattle, WA",
            EstimatedDelivery = null,
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "In transit to destination", Timestamp = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Delivered — signed by J. Smith", Timestamp = new DateTimeOffset(2026, 5, 22, 14, 35, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Los Angeles, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 20, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Timestamp = new DateTimeOffset(2026, 5, 27, 16, 0, 0, TimeSpan.Zero) },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_84271e90bece4b058355549cf0d4246c.Client.Models;

namespace sv_84271e90bece4b058355549cf0d4246c.Client.Services;

public sealed class HttpShipmentService(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var encoded = Uri.EscapeDataString(trackingNumber);
        var response = await http.GetAsync($"api/shipments/{encoded}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_84271e90bece4b058355549cf0d4246c.Client.Models
@using sv_84271e90bece4b058355549cf0d4246c.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h1>Shipment Tracker</h1>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <p>Loading shipment <strong>@TrackingNumber</strong>…</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div>
        <dl>
            <dt>Tracking Number</dt>
            <dd>@_shipment.TrackingNumber</dd>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@(_shipment.EstimatedDelivery?.ToString("f") ?? "N/A")</dd>
        </dl>

        <h2>Status Updates</h2>
        @if (_shipment.StatusUpdates.Count == 0)
        {
            <p>No status updates yet.</p>
        }
        else
        {
            <table class="table">
                <thead>
                    <tr>
                        <th>Time</th>
                        <th>Description</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var update in _shipment.StatusUpdates)
                    {
                        <tr>
                            <td>@update.Timestamp.ToString("g")</td>
                            <td>@update.Description</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request before starting a new one.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently stop.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

