                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 25, 10, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Arrived at sorting facility", Timestamp = new DateTimeOffset(2026, 5, 26, 3, 30, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Departed Memphis hub", Timestamp = new DateTimeOffset(2026, 5, 27, 14, 15, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "Seattle, WA",
            EstimatedDelivery = null,
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "In transit to destination", Timestamp = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Delivered — signed by J. Smith", Timestamp = new DateTimeOffset(2026, 5, 22, 14, 35, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Los Angeles, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 20, 0, 0, TimeSpan.Zero),
